#include "GAS/MyGameplayTags.h"
#include "GameplayTagsManager.h"

FMyGameplayTags FMyGameplayTags::Tags;

const FMyGameplayTags& FMyGameplayTags::Get()
{
    return Tags;
}

void FMyGameplayTags::InitializeNativeTags()
{
    UGameplayTagsManager& Manager = UGameplayTagsManager::Get();

    +GameplayTagList=(Tag="Ability.Attack.Charge",DevComment="")
+GameplayTagList=(Tag="Ability.Attack.Heavy",DevComment="")
+GameplayTagList=(Tag="Ability.Attack.Light",DevComment="약공격")
+GameplayTagList=(Tag="Ability.Attack.Melee",DevComment="")
+GameplayTagList=(Tag="Ability.Block",DevComment="")
+GameplayTagList=(Tag="Data.Damage",DevComment="")
+GameplayTagList=(Tag="Event.Montage.DealDamage",DevComment="")
+GameplayTagList=(Tag="State.Attacking",DevComment="")
+GameplayTagList=(Tag="State.Attacking.Heavy",DevComment="")
+GameplayTagList=(Tag="State.Attacking.Light",DevComment="")
+GameplayTagList=(Tag="State.Blocking",DevComment="")

    //=========================================================================
    // Character Tags 등록
    //=========================================================================

    Tags.Character_State_Jumping = Manager.AddNativeGameplayTag(
        FName("Character.State.Jumping"),
        FString("캐릭터가 점프 중인 상태")
    );

    Tags.Character_State_Attacking = Manager.AddNativeGameplayTag(
        FName("Character.State.Attacking"),
        FString("캐릭터가 공격 중인 상태")
    );

    Tags.Character_State_Blocking = Manager.AddNativeGameplayTag(
        FName("Character.State.Blocking"),
        FString("캐릭터가 블록 중인 상태")
    );

    Tags.Character_State_Dodging = Manager.AddNativeGameplayTag(
        FName("Character.State.Dodging"),
        FString("캐릭터가 회피 중인 상태")
    );

    //=========================================================================
    // Character Status Tags 등록
    //=========================================================================

    Tags.Character_Status_Invincible = Manager.AddNativeGameplayTag(
        FName("Character.Status.Invincible"),
        FString("무적 상태")
    );

    Tags.Character_Status_Stunned = Manager.AddNativeGameplayTag(
        FName("Character.Status.Stunned"),
        FString("스턴 상태")
    );

    //=========================================================================
    // Combat Tags 등록
    //=========================================================================

    Tags.Combat_Window_Combo = Manager.AddNativeGameplayTag(
        FName("Combat.Window.Combo"),
        FString("콤보 입력 가능 윈도우")
    );

    Tags.Combat_Window_Parry = Manager.AddNativeGameplayTag(
        FName("Combat.Window.Parry"),
        FString("패링 가능 윈도우")
    );

    //=========================================================================
    // Data Tags 등록
    //=========================================================================

    Tags.Data_Damage = Manager.AddNativeGameplayTag(
        FName("Data.Damage"),
        FString("SetByCaller용 데미지 Tag")
    );

    Tags.Data_StaminaCost = Manager.AddNativeGameplayTag(
        FName("Data.StaminaCost"),
        FString("SetByCaller용 스태미너 코스트 Tag")
    );
}

